    // Since n <= 10^9, n-1 is also around 10^9. cbrt(10^9) = 1000.
    const maxB = Math.floor(Math.cbrt(n));

    // Iterate through possible values of a
    for (let a = 1; a * a * a <= n; a++) {
        // Iterate through possible values of b, starting from a
        // We need a^3 + b^3 <= n, so b^3 <= n - a^3.
        const maxBForA = Math.floor(Math.cbrt(n - a * a * a));

        for (let b = a; b <= maxBForA; b++) {
